// =============================================
// ENCRYPTION UTILITIES
// =============================================
const Crypto = {
    // Simple XOR-based encryption with key (not production-grade, but provides user isolation)
    encrypt(text, key) {
      let result = '';
      for (let i = 0; i < text.length; i++) {
        result += String.fromCharCode(text.charCodeAt(i) ^ key.charCodeAt(i % key.length));
      }
      return btoa(result);
    },
    decrypt(encoded, key) {
      try {
        const text = atob(encoded);
        let result = '';
        for (let i = 0; i < text.length; i++) {
          result += String.fromCharCode(text.charCodeAt(i) ^ key.charCodeAt(i % key.length));
        }
        return result;
      } catch { return null; }
    },
    // Simple hash for passwords
    hash(str) {
      let h = 0;
      for (let i = 0; i < str.length; i++) h = (Math.imul(31, h) + str.charCodeAt(i)) | 0;
      return 'h' + Math.abs(h).toString(36) + str.length.toString(36);
    }
  };
  
  // =============================================
  // STORAGE
  // =============================================
  const Store = {
    getUsers() {
      try { return JSON.parse(localStorage.getItem('ff_users') || '[]'); } catch { return []; }
    },
    saveUsers(users) { localStorage.setItem('ff_users', JSON.stringify(users)); },
    
    getUserData(userId, encKey) {
      const raw = localStorage.getItem(`ff_data_${userId}`);
      if (!raw) return {};
      const dec = Crypto.decrypt(raw, encKey);
      if (!dec) return {};
      try { return JSON.parse(dec); } catch { return {}; }
    },
    saveUserData(userId, encKey, data) {
      const enc = Crypto.encrypt(JSON.stringify(data), encKey);
      localStorage.setItem(`ff_data_${userId}`, enc);
    },
    
    getConsent() { return localStorage.getItem('ff_consent') === '1'; },
    setConsent() { localStorage.setItem('ff_consent', '1'); }
  };
  
  // =============================================
  // APP STATE
  // =============================================
  let state = {
    currentUser: null,
    encKey: null,
    currentYear: new Date().getFullYear(),
    currentMonth: new Date().getMonth(), // 0-indexed
    currentView: 'dashboard',
    txPage: 0,
    txPerPage: 20
  };
  
  const MONTHS = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const MONTH_SHORT = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  
  // =============================================
  // INIT
  // =============================================
  function init() {
    // Always ensure correct admin account (Lati_254 / Psychosis)
    let users = Store.getUsers();
    
    // Remove any old admin entries (old 'admin'/'admin123' or wrong credentials)
    users = users.filter(u => u.role !== 'admin');
    
    // Add correct admin
    users.unshift({
      id: 'admin',
      name: 'Lati',
      username: 'lati_254',
      passwordHash: Crypto.hash('Psychosis'),
      role: 'admin',
      currency: 'KES',
      createdAt: '2026-01-01T00:00:00.000Z'
    });
    Store.saveUsers(users);
    
    // Seed admin's Excel data if not already present
    if (!localStorage.getItem('ff_data_admin')) {
      localStorage.setItem('ff_data_admin', '');
    }
  
    // Check consent
    if (!Store.getConsent()) {
      document.getElementById('consent-screen').style.display = 'flex';
      setupConsentListeners();
    } else {
      document.getElementById('consent-screen').style.display = 'none';
      showAuth();
    }
  }
  
  function setupConsentListeners() {
    const c1 = document.getElementById('consent-check1');
    const c2 = document.getElementById('consent-check2');
    const btn = document.getElementById('consent-btn');
    [c1, c2].forEach(c => c.addEventListener('change', () => {
      btn.disabled = !(c1.checked && c2.checked);
    }));
  }
  
  function acceptConsent() {
    Store.setConsent();
    document.getElementById('consent-screen').style.display = 'none';
    showAuth();
  }
  
  function showAuth() {
    document.getElementById('auth-screen').style.display = 'flex';
  }
  
  // =============================================
  // AUTH
  // =============================================
  function switchTab(tab) {
    document.querySelectorAll('.auth-tab').forEach((t,i) => t.classList.toggle('active', (i===0&&tab==='login')||(i===1&&tab==='register')));
    document.getElementById('login-form').style.display = tab === 'login' ? 'block' : 'none';
    document.getElementById('register-form').style.display = tab === 'register' ? 'block' : 'none';
  }
  
  function login() {
    const username = document.getElementById('login-user').value.trim().toLowerCase();
    const password = document.getElementById('login-pass').value;
    const users = Store.getUsers();
    const user = users.find(u => u.username === username && u.passwordHash === Crypto.hash(password));
    if (!user) {
      document.getElementById('login-error').style.display = 'block';
      return;
    }
    document.getElementById('login-error').style.display = 'none';
    startSession(user, password);
  }
  
  function register() {
    const name = document.getElementById('reg-name').value.trim();
    const username = document.getElementById('reg-user').value.trim().toLowerCase();
    const password = document.getElementById('reg-pass').value;
    const currency = document.getElementById('reg-currency').value;
    
    if (!name || !username || password.length < 6) {
      document.getElementById('reg-error').textContent = 'Please fill all fields (min 6 char password)';
      document.getElementById('reg-error').style.display = 'block';
      return;
    }
    const users = Store.getUsers();
    if (users.length >= 21) { // 20 users + 1 admin
      document.getElementById('reg-error').textContent = 'Maximum user limit (20) reached';
      document.getElementById('reg-error').style.display = 'block';
      return;
    }
    if (users.find(u => u.username === username)) {
      document.getElementById('reg-error').textContent = 'Username already taken';
      document.getElementById('reg-error').style.display = 'block';
      return;
    }
    const newUser = {
      id: 'u_' + Date.now(),
      name, username,
      passwordHash: Crypto.hash(password),
      role: 'user',
      currency,
      createdAt: new Date().toISOString()
    };
    users.push(newUser);
    Store.saveUsers(users);
    document.getElementById('reg-error').style.display = 'none';
    toast('Account created! Sign in now.', 'success');
    switchTab('login');
    document.getElementById('login-user').value = username;
  }
  
  function startSession(user, password) {
    state.currentUser = user;
    state.encKey = user.id + '_' + password; // encryption key = userId + password
    document.getElementById('auth-screen').style.display = 'none';
    document.getElementById('app').style.display = 'block';
    setupSidebar();
    renderMonthGrid();
    showView('dashboard');
    renderDashboard();
  }
  
  function logout() {
    state.currentUser = null;
    state.encKey = null;
    document.getElementById('app').style.display = 'none';
    document.getElementById('auth-screen').style.display = 'flex';
    document.getElementById('login-user').value = '';
    document.getElementById('login-pass').value = '';
  }
  
  // =============================================
  // SIDEBAR & NAVIGATION
  // =============================================
  function setupSidebar() {
    const u = state.currentUser;
    document.getElementById('sb-name').textContent = u.name;
    document.getElementById('sb-username').textContent = '@' + u.username;
    const isAdmin = u.role === 'admin';
    document.getElementById('sb-admin-badge').style.display = isAdmin ? 'inline-block' : 'none';
    document.getElementById('nav-admin').style.display = isAdmin ? 'flex' : 'none';
    document.getElementById('year-display').textContent = state.currentYear;
  }
  
  function renderMonthGrid() {
    const data = Store.getUserData(state.currentUser.id, state.encKey);
    const grid = document.getElementById('month-grid');
    grid.innerHTML = '';
    MONTH_SHORT.forEach((m, i) => {
      const key = `${state.currentYear}-${String(i+1).padStart(2,'0')}`;
      const hasData = data[key] && data[key].length > 0;
      const div = document.createElement('div');
      div.className = `month-chip ${hasData ? 'has-data' : ''} ${i === state.currentMonth ? 'active' : ''}`;
      div.textContent = m;
      div.onclick = () => { state.currentMonth = i; renderMonthGrid(); renderDashboard(); if(state.currentView==='transactions')renderTransactions(); if(state.currentView==='dashboard')showView('dashboard'); };
      grid.appendChild(div);
    });
  }
  
  function changeYear(delta) {
    state.currentYear += delta;
    document.getElementById('year-display').textContent = state.currentYear;
    renderMonthGrid();
    renderDashboard();
    if (state.currentView === 'yearly') renderYearly();
  }
  
  function showView(view) {
    state.currentView = view;
    ['dashboard','transactions','yearly','admin'].forEach(v => {
      document.getElementById(`view-${v}`).style.display = v === view ? 'block' : 'none';
      const nav = document.getElementById(`nav-${v}`);
      if (nav) nav.classList.toggle('active', v === view);
    });
    if (view === 'dashboard') renderDashboard();
    if (view === 'transactions') renderTransactions();
    if (view === 'yearly') renderYearly();
    if (view === 'admin') renderAdmin();
  }
  
  // =============================================
  // DATA HELPERS
  // =============================================
  function getMonthKey() {
    return `${state.currentYear}-${String(state.currentMonth+1).padStart(2,'0')}`;
  }
  
  function getTransactions() {
    const data = Store.getUserData(state.currentUser.id, state.encKey);
    return data[getMonthKey()] || [];
  }
  
  function saveTransactions(txs) {
    const data = Store.getUserData(state.currentUser.id, state.encKey);
    data[getMonthKey()] = txs;
    Store.saveUserData(state.currentUser.id, state.encKey, data);
  }
  
  function fmt(n) {
    const c = state.currentUser?.currency || 'KES';
    return `${c} ${Number(n||0).toLocaleString()}`;
  }
  
  function getMonthStats(txs) {
    const income = txs.filter(t => t.type === 'Revenue').reduce((s,t) => s + (t.amount||0), 0);
    const expense = txs.filter(t => t.type === 'Expenditure').reduce((s,t) => s + (t.amount||0), 0);
    const tc = txs.reduce((s,t) => s + (t.tc||0), 0);
    return { income, expense, net: income - expense, tc };
  }
  
  function getCategoryStats(txs) {
    const cats = {};
    txs.forEach(t => {
      if (!cats[t.category]) cats[t.category] = { exp: 0, rev: 0, count: 0 };
      cats[t.category].count++;
      if (t.type === 'Expenditure') cats[t.category].exp += (t.amount||0);
      else cats[t.category].rev += (t.amount||0);
    });
    return cats;
  }
  
  // =============================================
  // DASHBOARD
  // =============================================
  function renderDashboard() {
    const title = `${MONTHS[state.currentMonth]} ${state.currentYear}`;
    document.getElementById('dash-title').textContent = title;
    document.getElementById('dash-subtitle').textContent = 'Monthly Overview';
    document.getElementById('tx-title').textContent = title;
    document.getElementById('tx-subtitle').textContent = 'All transactions for this month';
    
    const txs = getTransactions();
    const stats = getMonthStats(txs);
    
    document.getElementById('stat-income').textContent = fmt(stats.income);
    document.getElementById('stat-income-count').textContent = `${txs.filter(t=>t.type==='Revenue').length} transactions`;
    document.getElementById('stat-expense').textContent = fmt(stats.expense);
    document.getElementById('stat-expense-count').textContent = `${txs.filter(t=>t.type==='Expenditure').length} transactions`;
    document.getElementById('stat-tc').textContent = fmt(stats.tc);
    document.getElementById('stat-tc-count').textContent = `${txs.filter(t=>t.tc>0).length} charges`;
    
    const netEl = document.getElementById('stat-net');
    const netCard = document.getElementById('stat-net-card');
    netEl.textContent = fmt(Math.abs(stats.net));
    netEl.style.color = stats.net >= 0 ? 'var(--income)' : 'var(--expense)';
    netCard.className = `stat-card stat-net ${stats.net>=0?'positive':'negative'}`;
    document.getElementById('stat-net-label').textContent = stats.net >= 0 ? '▲ surplus' : '▼ deficit';
    
    renderWeekCards(txs);
    renderCategoryCharts(txs);
    renderRecentTx(txs);
  }
  
  function renderWeekCards(txs) {
    const container = document.getElementById('week-cards');
    container.innerHTML = '';
    const weeks = {};
    txs.forEach(t => {
      const w = t.week || 'Other';
      if (!weeks[w]) weeks[w] = { exp:0, rev:0 };
      if (t.type === 'Expenditure') weeks[w].exp += (t.amount||0);
      else weeks[w].rev += (t.amount||0);
    });
    
    // Generate week labels for the month
    const year = state.currentYear;
    const month = state.currentMonth;
    const daysInMonth = new Date(year, month+1, 0).getDate();
    const weekLabels = [];
    for (let d = 1; d <= daysInMonth; d += 7) {
      const end = Math.min(d+6, daysInMonth);
      weekLabels.push(`${MONTH_SHORT[month]} ${d}–${end}`);
    }
    
    weekLabels.forEach((label, i) => {
      const wk = `WEEK ${i+1}`;
      const w = weeks[wk] || { exp:0, rev:0 };
      const div = document.createElement('div');
      div.className = 'week-card';
      div.innerHTML = `<div class="week-label">${wk}<br><span style="font-size:.65rem;color:var(--text3)">${label}</span></div>
        <div class="week-exp">${fmt(w.exp)}</div>
        <div class="week-rev">${fmt(w.rev)}</div>`;
      container.appendChild(div);
    });
  }
  
  function renderCategoryCharts(txs) {
    const cats = getCategoryStats(txs);
    const expEntries = Object.entries(cats).filter(([,v])=>v.exp>0).sort((a,b)=>b[1].exp-a[1].exp);
    const revEntries = Object.entries(cats).filter(([,v])=>v.rev>0).sort((a,b)=>b[1].rev-a[1].rev);
    const maxExp = expEntries[0]?.[1]?.exp || 1;
    const maxRev = revEntries[0]?.[1]?.rev || 1;
    
    function makeBar(entries, key, max, color) {
      if (!entries.length) return '<div style="color:var(--text3);font-size:.8rem;padding:12px 0">No data</div>';
      return entries.slice(0,8).map(([cat, v]) => `
        <div class="bar-row">
          <div class="bar-label">${cat}</div>
          <div class="bar-track"><div class="bar-fill" style="width:${(v[key]/max*100).toFixed(1)}%;background:${color}"></div></div>
          <div class="bar-val">${fmt(v[key])}</div>
        </div>`).join('');
    }
    
    document.getElementById('cat-chart-exp').innerHTML = makeBar(expEntries, 'exp', maxExp, 'var(--expense)');
    document.getElementById('cat-chart-rev').innerHTML = makeBar(revEntries, 'rev', maxRev, 'var(--income)');
    
    // Category cards
    const catWrap = document.getElementById('cat-grid-wrap');
    if (!Object.keys(cats).length) { catWrap.innerHTML = ''; return; }
    const cards = Object.entries(cats).sort((a,b) => b[1].exp - a[1].exp).map(([cat, v]) => `
      <div class="cat-card">
        <div class="cat-name">${cat}</div>
        ${v.exp > 0 ? `<div class="cat-exp">${fmt(v.exp)}</div>` : ''}
        ${v.rev > 0 ? `<div class="cat-rev">+${fmt(v.rev)}</div>` : ''}
        <div class="cat-freq">${v.count} transaction${v.count>1?'s':''}</div>
      </div>`).join('');
    catWrap.innerHTML = `<div class="cat-grid" style="margin-bottom:24px">${cards}</div>`;
  }
  
  function renderRecentTx(txs) {
    const wrap = document.getElementById('recent-tx-wrap');
    if (!txs.length) {
      wrap.innerHTML = `<div class="empty-state"><div class="empty-icon">📭</div><div class="empty-title">No transactions this month</div><div class="empty-sub">Add your first transaction above</div></div>`;
      return;
    }
    const rows = txs.slice(-10).reverse().map((t,i) => `
      <tr>
        <td>${t.date}</td>
        <td>${t.category}</td>
        <td>${t.description||'—'}</td>
        <td class="type-expense">${t.type==='Expenditure'?fmt(t.amount):'—'}</td>
        <td class="type-income">${t.type==='Revenue'?fmt(t.amount):'—'}</td>
        <td style="color:var(--tc)">${t.tc?fmt(t.tc):'—'}</td>
        <td><span class="badge ${t.type==='Expenditure'?'badge-exp':'badge-rev'}">${t.type}</span></td>
      </tr>`).join('');
    wrap.innerHTML = `<table><thead><tr><th>Date</th><th>Category</th><th>Description</th><th>Expenditure</th><th>Revenue</th><th>Tx Cost</th><th>Type</th></tr></thead><tbody>${rows}</tbody></table>`;
  }
  
  // =============================================
  // TRANSACTIONS VIEW
  // =============================================
  function renderTransactions() {
    const txs = getTransactions();
    const search = document.getElementById('tx-search').value.toLowerCase();
    const filterType = document.getElementById('tx-filter-type').value;
    const filterCat = document.getElementById('tx-filter-cat').value;
    const filterPay = document.getElementById('tx-filter-pay').value;
    
    // Update category filter
    const cats = [...new Set(txs.map(t=>t.category))].sort();
    const catSelect = document.getElementById('tx-filter-cat');
    const catVal = catSelect.value;
    catSelect.innerHTML = '<option value="">All Categories</option>' + cats.map(c=>`<option ${c===catVal?'selected':''}>${c}</option>`).join('');
    
    let filtered = txs.filter(t => {
      if (search && !((t.description||'').toLowerCase().includes(search) || t.category.toLowerCase().includes(search))) return false;
      if (filterType && t.type !== filterType) return false;
      if (filterCat && t.category !== filterCat) return false;
      if (filterPay && t.paymentMethod !== filterPay) return false;
      return true;
    });
    
    const total = filtered.length;
    const start = state.txPage * state.txPerPage;
    const page = filtered.slice(start, start + state.txPerPage);
    
    const tbody = document.getElementById('tx-table-body');
    if (!total) {
      tbody.innerHTML = `<tr><td colspan="9" style="text-align:center;padding:40px;color:var(--text3)">No transactions found</td></tr>`;
    } else {
      tbody.innerHTML = page.map((t, idx) => `
        <tr>
          <td>${t.date}</td>
          <td>${t.category}</td>
          <td>${t.description||'—'}</td>
          <td class="type-expense">${t.type==='Expenditure'?fmt(t.amount):'—'}</td>
          <td class="type-income">${t.type==='Revenue'?fmt(t.amount):'—'}</td>
          <td style="color:var(--tc)">${t.tc?fmt(t.tc):'—'}</td>
          <td>${t.paymentMethod||'—'}</td>
          <td><span class="badge ${t.type==='Expenditure'?'badge-exp':'badge-rev'}">${t.type}</span></td>
          <td><button class="btn-delete" onclick="deleteTransaction(${start+idx}, event)">🗑</button></td>
        </tr>`).join('');
    }
    
    // Pagination
    const pages = Math.ceil(total / state.txPerPage);
    const pag = document.getElementById('tx-pagination');
    pag.innerHTML = '';
    if (pages > 1) {
      for (let p = 0; p < pages; p++) {
        const btn = document.createElement('button');
        btn.style.cssText = `padding:6px 12px;background:${p===state.txPage?'var(--accent)':'var(--surface2)'};color:${p===state.txPage?'#0a0c10':'var(--text2)'};border:1px solid var(--border);border-radius:6px;cursor:pointer;font-family:'Syne',sans-serif;font-size:.8rem`;
        btn.textContent = p + 1;
        btn.onclick = () => { state.txPage = p; renderTransactions(); };
        pag.appendChild(btn);
      }
    }
  }
  
  function deleteTransaction(globalIdx, e) {
    e.stopPropagation();
    const txs = getTransactions();
    const search = document.getElementById('tx-search').value.toLowerCase();
    const filterType = document.getElementById('tx-filter-type').value;
    const filterCat = document.getElementById('tx-filter-cat').value;
    const filterPay = document.getElementById('tx-filter-pay').value;
    let filtered = txs.filter(t => {
      if (search && !((t.description||'').toLowerCase().includes(search) || t.category.toLowerCase().includes(search))) return false;
      if (filterType && t.type !== filterType) return false;
      if (filterCat && t.category !== filterCat) return false;
      if (filterPay && t.paymentMethod !== filterPay) return false;
      return true;
    });
    const toDelete = filtered[globalIdx];
    const idx = txs.indexOf(toDelete);
    if (idx > -1) {
      txs.splice(idx, 1);
      saveTransactions(txs);
      toast('Transaction deleted', 'success');
      renderTransactions();
      renderMonthGrid();
    }
  }
  
  // =============================================
  // YEARLY VIEW
  // =============================================
  function renderYearly() {
    document.getElementById('yearly-title').textContent = `${state.currentYear} Overview`;
    const data = Store.getUserData(state.currentUser.id, state.encKey);
    
    let yrIncome = 0, yrExpense = 0, yrTc = 0;
    const monthsGrid = document.getElementById('yearly-months-grid');
    monthsGrid.innerHTML = '';
    
    const chartData = [];
    
    MONTHS.forEach((m, i) => {
      const key = `${state.currentYear}-${String(i+1).padStart(2,'0')}`;
      const txs = data[key] || [];
      const stats = getMonthStats(txs);
      yrIncome += stats.income;
      yrExpense += stats.expense;
      yrTc += stats.tc;
      chartData.push({ month: MONTH_SHORT[i], income: stats.income, expense: stats.expense });
      
      const card = document.createElement('div');
      card.className = `month-summary-card ${!txs.length ? 'empty' : ''}`;
      card.innerHTML = `<div class="mscard-name">${m}</div>
        <div class="mscard-income">+${fmt(stats.income)}</div>
        <div class="mscard-expense">-${fmt(stats.expense)}</div>
        <div class="mscard-net">${stats.net>=0?'▲':'▼'} ${fmt(Math.abs(stats.net))}</div>`;
      card.onclick = () => { state.currentMonth = i; renderMonthGrid(); showView('dashboard'); };
      monthsGrid.appendChild(card);
    });
    
    document.getElementById('yr-income').textContent = fmt(yrIncome);
    document.getElementById('yr-expense').textContent = fmt(yrExpense);
    const yrNet = yrIncome - yrExpense;
    const yrNetEl = document.getElementById('yr-net');
    yrNetEl.textContent = fmt(Math.abs(yrNet));
    yrNetEl.style.color = yrNet >= 0 ? 'var(--income)' : 'var(--expense)';
    document.getElementById('yr-tc').textContent = fmt(yrTc);
    
    // Bar chart
    const maxVal = Math.max(...chartData.map(d => Math.max(d.income, d.expense)), 1);
    const chartEl = document.getElementById('yearly-bar-chart');
    chartEl.innerHTML = chartData.map(d => `
      <div style="display:grid;grid-template-columns:60px 1fr 1fr 80px 80px;gap:8px;align-items:center;margin-bottom:6px">
        <div style="font-size:.75rem;color:var(--text2);font-family:'DM Mono',monospace">${d.month}</div>
        <div><div style="height:10px;background:var(--income);width:${(d.income/maxVal*100).toFixed(1)}%;border-radius:4px;min-width:${d.income?'4px':'0'}"></div></div>
        <div><div style="height:10px;background:var(--expense);width:${(d.expense/maxVal*100).toFixed(1)}%;border-radius:4px;min-width:${d.expense?'4px':'0'}"></div></div>
        <div style="font-family:'DM Mono',monospace;font-size:.72rem;color:var(--income)">${fmt(d.income)}</div>
        <div style="font-family:'DM Mono',monospace;font-size:.72rem;color:var(--expense)">${fmt(d.expense)}</div>
      </div>`).join('');
  }
  
  // =============================================
  // ADMIN VIEW
  // =============================================
  function renderAdmin() {
    const users = Store.getUsers();
    document.getElementById('admin-user-count').textContent = users.length;
    
    let totalTx = 0;
    users.forEach(u => {
      // Admin can see transaction counts (not content)
      const raw = localStorage.getItem(`ff_data_${u.id}`);
      if (raw) {
        // We can at least count how many month keys exist
        try {
          // Admin uses their own key so they can't decrypt user data — by design
          totalTx += 1;
        } catch {}
      }
    });
    
    const adminUser = users.find(u => u.role === 'admin');
    document.getElementById('admin-since').textContent = adminUser ? new Date(adminUser.createdAt).getFullYear() : '—';
    document.getElementById('admin-tx-count').textContent = users.filter(u => localStorage.getItem(`ff_data_${u.id}`)).length + ' accounts with data';
    
    const list = document.getElementById('admin-users-list');
    list.innerHTML = users.map(u => `
      <div class="user-row">
        <div>
          <div class="user-name">${u.name}</div>
          <div class="user-username">@${u.username}</div>
        </div>
        <div><span class="badge-role ${u.role==='admin'?'role-admin':'role-user'}">${u.role.toUpperCase()}</span></div>
        <div style="font-size:.75rem;color:var(--text3);font-family:'DM Mono',monospace">${u.currency}</div>
        <div style="font-size:.75rem;color:var(--text3);font-family:'DM Mono',monospace">${new Date(u.createdAt).toLocaleDateString()}</div>
        <div style="display:flex;gap:6px">
          ${u.role !== 'admin' ? `<button class="btn-delete-user" onclick="deleteUser('${u.id}')">Delete</button>` : '<span style="font-size:.75rem;color:var(--text3)">Admin</span>'}
        </div>
      </div>`).join('');
  }
  
  function deleteUser(userId) {
    if (!confirm('Delete this user and all their data?')) return;
    let users = Store.getUsers();
    users = users.filter(u => u.id !== userId);
    Store.saveUsers(users);
    localStorage.removeItem(`ff_data_${userId}`);
    toast('User deleted', 'success');
    renderAdmin();
  }
  
  // =============================================
  // MODAL & TRANSACTIONS
  // =============================================
  function openModal() {
    const today = new Date();
    document.getElementById('tx-date').value = `${state.currentYear}-${String(state.currentMonth+1).padStart(2,'0')}-${String(today.getDate()).padStart(2,'0')}`;
    document.getElementById('tx-amount').value = '';
    document.getElementById('tx-tc').value = '';
    document.getElementById('tx-desc').value = '';
    document.getElementById('tx-modal').classList.add('open');
  }
  
  function closeModal() {
    document.getElementById('tx-modal').classList.remove('open');
  }
  
  function saveTransaction() {
    const date = document.getElementById('tx-date').value;
    const category = document.getElementById('tx-cat').value;
    const type = document.getElementById('tx-type').value;
    const description = document.getElementById('tx-desc').value.trim();
    const amount = parseFloat(document.getElementById('tx-amount').value) || 0;
    const tc = parseFloat(document.getElementById('tx-tc').value) || 0;
    const paymentMethod = document.getElementById('tx-pay').value;
    
    if (!date || !amount) { toast('Please enter a date and amount', 'error'); return; }
    
    // Determine week
    const day = new Date(date).getDate();
    let week = 'WEEK 1';
    if (day > 28) week = 'WEEK 5';
    else if (day > 21) week = 'WEEK 4';
    else if (day > 14) week = 'WEEK 3';
    else if (day > 7) week = 'WEEK 2';
    
    const txs = getTransactions();
    txs.push({ date, category, type, description, amount, tc, paymentMethod, week, id: Date.now() });
    txs.sort((a,b) => new Date(a.date) - new Date(b.date));
    saveTransactions(txs);
    
    closeModal();
    toast('Transaction saved!', 'success');
    renderMonthGrid();
    if (state.currentView === 'dashboard') renderDashboard();
    if (state.currentView === 'transactions') renderTransactions();
  }
  
  // =============================================
  // TOAST
  // =============================================
  function toast(msg, type='success') {
    const t = document.createElement('div');
    t.className = `toast toast-${type}`;
    t.textContent = msg;
    document.getElementById('toast-container').appendChild(t);
    setTimeout(() => t.remove(), 3000);
  }
  
  // Close modal on backdrop click
  document.getElementById('tx-modal').addEventListener('click', e => {
    if (e.target === e.currentTarget) closeModal();
  });
  
  // Enter key for login
  document.addEventListener('keydown', e => {
    if (e.key === 'Enter') {
      if (document.getElementById('auth-screen').style.display !== 'none') {
        login();
      }
    }
  });
  
  init();